// Parse AI JSON output and prepare for fal.ai
const raw    = $input.first().json.output || '';
const email  = $('1. Form — Video Request').first().json['Your Email Address'] || '';
const idea   = $('1. Form — Video Request').first().json['Video Idea'] || '';
const style  = $('1. Form — Video Request').first().json['Video Style'] || '';

let parsed = { title: 'Generated Video', prompt: '' };
try {
  const cleaned = raw.trim()
    .replace(/^```json\s*/i, '')
    .replace(/^```\s*/i, '')
    .replace(/```$/i, '')
    .trim();
  parsed = JSON.parse(cleaned);
} catch (e) {
  parsed = {
    title: 'Generated Video ' + Date.now(),
    prompt: raw.substring(0, 500) || idea
  };
}

const safeTitle = (parsed.title || 'video')
  .replace(/[^a-zA-Z0-9 _-]/g, '')
  .replace(/\s+/g, '_')
  .substring(0, 60);

return [{
  json: {
    email,
    videoIdea:   idea,
    videoStyle:  style,
    title:       parsed.title  || 'Generated Video',
    safeTitle:   safeTitle,
    prompt:      parsed.prompt || idea,
    aspectRatio: '16:9',
    duration:    '8s'
  }
}];
